import{_ as l,o as e,c as i,a2 as t}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),r={name:"審計報告庫/財務審計/6261_久元/20260424/F17_籌碼分佈與法人動態分析_投資研究員.md"};function o(n,a,s,_,h,d){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="f17-籌碼分佈與法人動態分析-投資研究員-審計報告" tabindex="-1">F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析-投資研究員-審計報告" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>執行法人對決與籌碼集中度審計，分析三大法人的合計進出趨勢，判定資金是否具備共識性合力。識別散戶與法人的籌碼換手特徵，預警派發期風險或捕捉收集期機會。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至 2026 年 4 月 23 日之法人買賣超與 2026 年 4 月 17 日股權分散表最新數據，久元呈現「外資高度活躍但方向分歧、大戶持續鎖碼」格局。近一個月外資累計淨買超約 41 萬張（金額 25-30 億元），但最後兩日（4/21-4/23）出現明顯賣壓（淨賣超約 282 萬張），而千張大戶比例在同期間從 34.31% 續升至 34.53%，籌碼結構仍屬主力鎖碼格局。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：A（良）</strong></p><p>關鍵數據基石：</p><ul><li>近一個月（2026/03/18-04/23）外資累計買進 1,592 萬張，賣出 1,551 萬張，淨買超 +40.99 萬張</li><li>近四週（2026/03/27-04/23）外資淨買超 +23.89 萬張，交易量極大（單日頻繁超過 30 萬張）</li><li>投信：無任何交易記錄（三年來完全缺席）</li><li>自營商避險：近一個月淨買超 +152.86 萬張（四週 +152.86 萬張），高度參與</li><li>千張大戶比例趨勢：30.16%（03/20）→ 34.31%（04/10）→ 34.53%（04/17），持續攀升</li><li>400 張以上大戶：36.95%（03/20）→ 42.16%（04/10）→ 42.98%（04/17），三週內暴增 +6.03 個百分點</li><li>散戶（1-999 張）持股比例僅 0.5%，但人數從 18,948 增至 35,964 人</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-三大法人近期買賣超動向" tabindex="-1">1. 三大法人近期買賣超動向 <a class="header-anchor" href="#_1-三大法人近期買賣超動向" aria-label="Permalink to &quot;1. 三大法人近期買賣超動向&quot;">​</a></h3><p>久元在外資券商中屬高度活躍標的，平均日成交量動輒數萬張（含避險操作）：</p><ul><li><strong>外資</strong>：呈「高週轉、小淨買」格局。買賣雙向均巨大，反映外資進行大量程式交易與避險操作。進入 4 月下旬後，4/21（買 224 萬/賣 305 萬）、4/22（買 146 萬/賣 163 萬）、4/23（買 237 萬/賣 390 萬）連續三日淨賣超，賣壓加大。</li><li><strong>投信</strong>：三年內完全無進出記錄，此為久元非投信偏好標的之明確證據。</li><li><strong>自營商（避險）</strong>：近一個月淨買超 152.86 萬張，高度參與，但主要為搭配權證或可轉債的避險單，不代表方向性看好。</li></ul><h3 id="_2-千張大戶持股比例的結構性變化" tabindex="-1">2. 千張大戶持股比例的結構性變化 <a class="header-anchor" href="#_2-千張大戶持股比例的結構性變化" aria-label="Permalink to &quot;2. 千張大戶持股比例的結構性變化&quot;">​</a></h3><p>久元在近三週出現極度強勁的大戶集中化：</p><ul><li>千張大戶：30.16%（03/20）→ 34.31%（04/10，+4.15pp）→ 34.53%（04/17，+0.22pp）</li><li>扣掉千張以外之 400 張以上大戶：6.79%（03/20）→ 7.85%（04/10）→ 8.45%（04/17）</li><li>這顯示除了頂層千張大戶持續加碼外，中層大戶（400-1000 張）也在同步收籌碼</li></ul><p>3 年前的對比：千張大戶僅 25.03%（2023/04）→ 現在 34.53%（+9.5pp），這三年的集中化幅度極大。</p><h3 id="_3-鎖碼-派發特徵判定" tabindex="-1">3. 鎖碼/派發特徵判定 <a class="header-anchor" href="#_3-鎖碼-派發特徵判定" aria-label="Permalink to &quot;3. 鎖碼/派發特徵判定&quot;">​</a></h3><p>從籌碼特徵來看：</p><ul><li>大戶持股創 12 週新高（最新 34.53% vs 三週前 30.16%）</li><li>散戶人數暴增 89.8% 但持股比例僅 0.5%（幾乎無足輕重）</li><li>並未出現「股價漲、大戶退、散戶接」的典型派發訊號</li></ul><p><strong>結論：仍處於收集期尾聲，尚未進入派發階段。</strong></p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>久元的籌碼面存在一個獨特的矛盾結構：外資高週轉 vs 大戶持續鎖碼。</p><p><strong>散戶陷阱評估</strong>：散戶人數暴增但持股比例極低（0.5%），代表新進散戶多為極小額買進，並未構成實質賣壓。這與典型的高位派發格局（散戶持有 15-30% 籌碼）完全不同。</p><p><strong>投信缺席的意義</strong>：成長股或機構偏好股通常會吸引投信進場。久元投信歸零，說明其市場定位偏向價值型（高殖利率防禦股），而非成長型標的。外資的進出波動因此成為法人面的主要觀察維度。</p><p><strong>風險預警</strong>：4/21-4/23 外資連續三日淨賣超約 282 萬張，若此趨勢延續至下週（累計淨賣超逾 500 萬張），將構成短期調節訊號。但在千張大戶仍持續增持的前提下，此為正常獲利了結而非出貨。</p><p><strong>鎖碼潛力評估</strong>：400 張以上大戶已達 42.98%，加上其他穩定的董監持股，市場實際流通在外籌碼可能已低於 50%。當鎖碼程度突破 50% 時，股價將具有「少數買盤即可推動大漲」的物理特性。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><code>數據採集器查詢</code>: institutional 6261 2026-02-24 2026-04-24 (科目：三大法人每日買賣超，外資為主要參與者)</li><li><code>數據採集器查詢</code>: backer_holding 6261 2026-03-01 2026-04-24 (科目：2026/03/20, 04/10, 04/17 三日股權分散表)</li><li><code>物理數值校準</code>：已確認 2026/04/17 千張大戶 34.53% 及 400 張以上 42.98% 為直接原始數據</li><li><code>物理數值校準</code>：已確認外資買賣超數據與股權分散表日期一致，無時間錯配</li></ul>',29)])])}const u=l(r,[["render",o]]);export{c as __pageData,u as default};
